import { fetchArticles, fetchArticle as fetchArticleApi, fetchAdminArticles, searchArticlesBackend, type ApiArticleSummary, type ApiArticle } from './api'
import type { ArticleSummary } from '@/components/blog/article-card'

// ── Re-export Article type for convenience ────────────────────────────────────
export type { ArticleSummary }

// ── Internal helpers ──────────────────────────────────────────────────────────

/** Full article with content (returned by getArticleBySlug) */
export interface Article extends ArticleSummary {
  content: string
}

/** Map API article summary → frontend ArticleSummary (matches ArticleCard) */
function mapSummary(a: ApiArticleSummary): ArticleSummary {
  return {
    slug: a.slug,
    title: a.title,
    excerpt: a.excerpt ?? '',
    category: a.category ?? 'ctdl',
    tags: Array.isArray(a.tags) ? a.tags : [],
    hero: a.coverImage ?? null,
    author: a.author?.name ?? 'MAIY Tech Hub',
    readingTime: a.readingTime ?? 5,
    publishedAt: a.publishedAt ?? new Date().toISOString(),
  }
}

/** Map API full article → frontend Article (with content) */
function mapArticle(a: ApiArticle): Article {
  return {
    ...mapSummary(a),
    content: a.content ?? '',
  }
}

// ── Public API (mirrors old MDX interface) ───────────────────────────────────

export async function getAllArticles(): Promise<ArticleSummary[]> {
  try {
    const res = await fetchArticles({ limit: 100 })
    return res.articles.map(mapSummary)
  } catch (err) {
    console.error('[content] getAllArticles failed:', err)
    return []
  }
}

/** All tags with article count, sorted by frequency */
export interface TagCount { tag: string; count: number }
export async function getAllTags(): Promise<TagCount[]> {
  try {
    const res = await fetchArticles({ limit: 1000 })
    const tagCounts: Record<string, number> = {}
    for (const a of res.articles) {
      for (const tag of (a.tags ?? [])) {
        tagCounts[tag] = (tagCounts[tag] || 0) + 1
      }
    }
    return Object.entries(tagCounts)
      .map(([tag, count]) => ({ tag, count }))
      .sort((a, b) => b.count - a.count)
  } catch {
    return []
  }
}

/** Search articles by query — uses backend search param + client-side tag filter */
export async function searchArticles(query: string): Promise<ArticleSummary[]> {
  if (!query.trim()) return []
  try {
    // Try backend search first
    const articles = await searchArticlesBackend(query, 50)
    // Backend doesn't search tags, so also filter client-side by tag
    const q = query.toLowerCase()
    return articles
      .filter(
        (a) =>
          a.title.toLowerCase().includes(q) ||
          (a.excerpt ?? '').toLowerCase().includes(q) ||
          (a.tags ?? []).some((t) => t.toLowerCase().includes(q))
      )
      .map(mapSummary)
  } catch {
    return []
  }
}

