export type PeerEvent =
  | { type: 'peer-joined'; peerId: string; peerName: string; stream?: MediaStream }
  | { type: 'peer-left'; peerId: string }
  | { type: 'offer'; from: string; sdp: RTCSessionDescriptionInit }
  | { type: 'answer'; from: string; sdp: RTCSessionDescriptionInit }
  | { type: 'ice-candidate'; from: string; candidate: RTCIceCandidateInit }
  | { type: 'chat-message'; from: string; fromName: string; text: string; timestamp: number }
  | { type: 'screen-share'; from: string; sharing: boolean }
  | { type: 'connected'; peerId: string }
  | { type: 'disconnected' }
  | { type: 'error'; message: string }

export type PeerEventHandler = (event: PeerEvent) => void

export async function createPeerConnection(
  peerId: string,
  peerName: string,
  onEvent: PeerEventHandler,
  localStream?: MediaStream
): Promise<PeerConnection> {
  const pc = new RTCPeerConnection(RTC_CONFIG)
  const peer: PeerConnection = {
    peerId,
    peerName,
    connection: pc,
  }

  // Handle ICE candidates
  pc.onicecandidate = (e) => {
    if (e.candidate) {
      onEvent({
        type: 'ice-candidate',
        from: peerId,
        candidate: e.candidate.toJSON(),
      })
    }
  }

  // Handle incoming stream
  pc.ontrack = (e) => {
    const [remoteStream] = e.streams
    if (remoteStream) {
      peer.stream = remoteStream
      peer.videoTrack = remoteStream.getVideoTracks()[0]
      peer.audioTrack = remoteStream.getAudioTracks()[0]
      onEvent({
        type: 'peer-joined',
        peerId,
        peerName,
        stream: remoteStream,
      })
    }
  }

  // Connection state
  pc.onconnectionstatechange = () => {
    if (pc.connectionState === 'connected') {
      onEvent({ type: 'connected', peerId })
    } else if (
      pc.connectionState === 'disconnected' ||
      pc.connectionState === 'failed'
    ) {
      onEvent({ type: 'disconnected' })
    }
  }

  // Add local tracks
  if (localStream) {
    localStream.getTracks().forEach((track) => {
      pc.addTrack(track, localStream)
    })
    peer.stream = localStream
    peer.videoTrack = localStream.getVideoTracks()[0]
    peer.audioTrack = localStream.getAudioTracks()[0]
  }

  return peer
}

export async function createOffer(pc: RTCPeerConnection): Promise<RTCSessionDescriptionInit> {
  const offer = await pc.createOffer()
  await pc.setLocalDescription(offer)
  return offer
}

export async function createAnswer(
  pc: RTCPeerConnection,
  offer: RTCSessionDescriptionInit
): Promise<RTCSessionDescriptionInit> {
  await pc.setRemoteDescription(new RTCSessionDescription(offer))
  const answer = await pc.createAnswer()
  await pc.setLocalDescription(answer)
  return answer
}

export async function handleAnswer(
  pc: RTCPeerConnection,
  answer: RTCSessionDescriptionInit
): Promise<void> {
  await pc.setRemoteDescription(new RTCSessionDescription(answer))
}

export async function addIceCandidate(
  pc: RTCPeerConnection,
  candidate: RTCIceCandidateInit
): Promise<void> {
  await pc.addIceCandidate(new RTCIceCandidate(candidate))
}

export async function getLocalStream(
  video: boolean = true,
  audio: boolean = true
): Promise<MediaStream | null> {
  try {
    const stream = await navigator.mediaDevices.getUserMedia({
      video: video
        ? { width: { ideal: 1280 }, height: { ideal: 720 }, facingMode: 'user' }
        : false,
      audio: audio ? { echoCancellation: true, noiseSuppression: true } : false,
    })
    return stream
  } catch (err) {
    console.warn('MediaDevices error:', err)
    return null
  }
}

export async function getScreenStream(): Promise<MediaStream | null> {
  try {
    const stream = await navigator.mediaDevices.getDisplayMedia({
      video: { cursor: 'always' } as MediaTrackConstraints,
      audio: false,
    })
    return stream
  } catch {
    return null
  }
}

export function stopStream(stream?: MediaStream) {
  stream?.getTracks().forEach((t) => t.stop())
}

export function toggleTrack(track?: MediaStreamTrack, enabled?: boolean) {
  if (track) track.enabled = enabled ?? !track.enabled
}
